L'option à activer est `experimentalDecorators` et elle doit être définie à `true`. La configuration complète est :
```json
{
  "compilerOptions": {
    "experimentalDecorators": true
  }
}
```
Il est également recommandé d'activer `emitDecoratorMetadata` pour utiliser les métadonnées des décorateurs.

```typescript
function Logger(className: string) {
  return function (constructor: Function) {
    const originalConstructor = constructor;

    const newConstructor: any = function (...args: any[]) {
      const instance = new originalConstructor(...args);
      const date = new Date().toLocaleString();
      console.log(`[${className}] Instance créée à ${date}`);
      return instance;
    };

    newConstructor.prototype = originalConstructor.prototype;
    return newConstructor;
  };
}
```
Ou une version plus simple en remplaçant directement le constructeur.

```typescript
function AutoriserRole(rolesAutorises: string[]) {
  return function (
    target: any,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const methodeOriginale = descriptor.value;

    descriptor.value = function (...args: any[]) {
      if (rolesAutorises.includes(this.userRole)) {
        return methodeOriginale.apply(this, args);
      } else {
        console.error("Accès refusé : rôle insuffisant");
        return null;
      }
    };

    return descriptor;
  };
}

// Utilisation
class BanqueService {
  userRole: string;

  constructor(role: string) {
    this.userRole = role;
  }

  @AutoriserRole(['admin', 'manager'])
  effectuerVirement(montant: number, destinataire: string) {
    console.log(`Virement de ${montant}€ à ${destinataire} effectué`);
  }
}
```

```typescript
function MinLength(min: number) {
  return function (target: any, propertyKey: string) {
    let valeur: string;

    const getter = function () {
      return valeur;
    };

    const setter = function (nouvelleValeur: string) {
      if (nouvelleValeur.length < min) {
        throw new Error(
          `La propriété ${propertyKey} doit contenir au moins ${min} caractères. ` +
          `Valeur actuelle : "${nouvelleValeur}" (${nouvelleValeur.length} caractères)`
        );
      }
      valeur = nouvelleValeur;
    };

    Object.defineProperty(target, propertyKey, {
      get: getter,
      set: setter,
      enumerable: true,
      configurable: true
    });
  };
}

// Utilisation
class Utilisateur {
  @MinLength(3)
  nom: string;

  constructor(nom: string) {
    this.nom = nom;
  }
}

const user = new Utilisateur("Alice"); // OK
const user2 = new Utilisateur("Bo"); // Erreur : doit contenir au moins 3 caractères
```

```typescript
// Conteneur d'injection
class Container {
  private static services = new Map<string, any>();

  static register(name: string, service: any) {
    this.services.set(name, service);
  }

  static get(name: string) {
    const service = this.services.get(name);
    if (!service) {
      throw new Error(`Service ${name} non trouvé`);
    }
    return service;
  }
}

// Décorateur de paramètre
const INJECTION_METADATA_KEY = Symbol('inject_params');

function Inject(serviceName: string) {
  return function (target: any, methodName: string, parameterIndex: number) {
    const existingInjections = Reflect.getOwnMetadata(INJECTION_METADATA_KEY, target, methodName) || [];
    existingInjections.push({ index: parameterIndex, serviceName });
    Reflect.defineMetadata(INJECTION_METADATA_KEY, existingInjections, target, methodName);
  };
}

// Fonction pour wrapper les méthodes avec injection
function applyInjection(target: any) {
  const prototype = target.prototype;
  const methodNames = Object.getOwnPropertyNames(prototype).filter(
    name => name !== 'constructor' && typeof prototype[name] === 'function'
  );

  methodNames.forEach(methodName => {
    const originalMethod = prototype[methodName];
    const injections = Reflect.getOwnMetadata(INJECTION_METADATA_KEY, prototype, methodName) || [];

    prototype[methodName] = function (...args: any[]) {
      injections.forEach((injection: any) => {
        args[injection.index] = Container.get(injection.serviceName);
      });
      return originalMethod.apply(this, args);
    };
  });
}

// Utilisation
class UserService {
  getUsers() {
    return ['Alice', 'Bob', 'Charlie'];
  }
}

Container.register('UserService', new UserService());

@applyInjection
class UserController {
  getUser(@Inject('UserService') userService: any) {
    return userService.getUsers();
  }
}

const controller = new UserController();
console.log(controller.getUser()); // ['Alice', 'Bob', 'Charlie']
```
*Note : Cette implémentation nécessite l'activation de `emitDecoratorMetadata` et l'installation de `reflect-metadata`.*
